sys_ws_operation.operation_script:
(function process(request, response) {
      var token = request.queryParams.token;
      if (Array.isArray(token)) token = token[0];

      response.setContentType('text/html');

      if (!token) return _html(response, 400, 'Token ausente', 'Link invalido (sem token).');

      var mlt = new x_1880990_chain.MagicLinkToken();
      var v = mlt.verify(token);
      if (!v.valid) {
          return _html(response, 401, 'Link invalido', 'Token invalido ou expirado.');
      }

      if (v.payload.a !== 'counter_reject') {
          return _html(response, 400, 'Acao invalida', 'Este link nao corresponde a recusar contraproposta.');
      }

      var p = new GlideRecord('x_1880990_chain_proposal');
      if (!p.get(v.payload.p)) return _html(response, 404, 'Proposta nao encontrada', 'A proposta nao existe.');

      if (p.state.toString() !== '30') {
          return _html(response, 409, 'Estado invalido',
              'A proposta nao esta mais em contraproposta (estado atual: ' + p.state.toString() + ').');
      }

      if (p.buyer.toString() !== v.payload.o) {
          return _html(response, 403, 'Permissao negada', 'Voce nao e o comprador desta proposta.');
      }

      p.state = 40;
      p.work_notes = 'Buyer recusou contraproposta de R$ ' + p.counter_offer + '. Negociacao encerrada.';
      p.update();

      return _html(response, 200, 'Contraproposta recusada',
          'Voce recusou a contraproposta da proposta ' + p.number + '. A negociacao foi encerrada. Voce pode fechar esta janela.');

      function _html(response, status, title, message) {
          response.setStatus(status);
          var color = status === 200 ? '#c0392b' : '#c0392b';
          var body =  
              '<html><head><meta charset="utf-8"><title>' + title + '</title></head>' +
              '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 80px auto; text-align: center;">' +
              '<h1 style="color: ' + color + ';">' + title + '</h1>' +
              '<p style="font-size: 1.1em; color: #333;">' + message + '</p>' +
              '<p style="color: #888; font-size: 12px; margin-top: 32px;">Chain Academy &mdash; Detran SP</p>' +
              '</body></html>';
          response.getStreamWriter().writeString(body);
      }
  })(request, response);
